/// SequenceTemplate — static definition of a guided multi-screen sequence.
///
/// Immutable. Defined in code, not generated by LLM.
/// The LLM decides the intent; the CODE maps intent → template.
///
/// See: docs/RFC_AGENT_LOOP_STATEFUL.md §3.1–3.2
library;

// ════════════════════════════════════════════════════════════════
//  STEP DEFINITION
// ════════════════════════════════════════════════════════════════

/// One step definition inside a SequenceTemplate.
///
/// Immutable. Maps to a ScreenRegistry intent tag (semantic, not a route).
class SequenceStepDef {
  /// Stable unique identifier for this step (e.g. 'housing_01_affordability').
  final String id;

  /// 1-based display order in the sequence.
  final int order;

  /// Semantic intent tag — maps to ScreenRegistry (e.g. 'housing_purchase').
  /// Resolved to a route via MintScreenRegistry.findByIntentStatic().
  final String intentTag;

  /// ARB key for the step title (displayed in SequenceProgressCard).
  final String titleKey;

  /// Maps output keys from this step's ScreenReturn.stepOutputs
  /// to input keys expected by the next step's prefill.
  ///
  /// Example: {'capacite_achat': 'montant_bien_cible'}
  /// means this step's output 'capacite_achat' becomes the next step's
  /// prefill key 'montant_bien_cible'.
  final Map<String, String> outputMapping;

  /// Whether this step can be skipped without blocking the sequence.
  final bool isOptional;

  const SequenceStepDef({
    required this.id,
    required this.order,
    required this.intentTag,
    required this.titleKey,
    this.outputMapping = const {},
    this.isOptional = false,
  });
}

